struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // 1. Create a buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // 2. Use the buffer_adaptor's copy function to preview the first byte (data_type) without advancing the read pointer
    adaptor.copy(&result.data_type, sizeof(uint8_t));

    // 3. Calculate the total data size needed for reading
    // Header: 1 byte (data_type) + 4 bytes (item_count)
    // Items: item_count * 4 bytes (each uint32_t or float is 4 bytes)

    // 4. Check if the buffer has enough data for the header (5 bytes)
    if (adaptor.size() < 5) {
        return result; // Return empty result if insufficient data for header
    }

    // Read the item_count (advances read pointer)
    uint32_t item_count;
    adaptor.copy(&item_count, sizeof(uint32_t));

    // 5. Check if the buffer has enough data for the items
    size_t total_item_size = item_count * sizeof(uint32_t);
    if (adaptor.size() < 5 + total_item_size) {
        return result; // Return partial result if insufficient data for items
    }

    // 6. Read the items based on data_type
    if (result.data_type == 0) { // Integers
        result.int_items.resize(item_count);
        adaptor.copy(result.int_items.data(), total_item_size);
    } else if (result.data_type == 1) { // Floats
        result.float_items.resize(item_count);
        adaptor.copy(result.float_items.data(), total_item_size);
    }

    return result;
}
