    // Create buffer_read_adaptor for the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check the size of data available to read using size()
    std::size_t available_size = read_adaptor.size();

    // Read the data back into a new vector
    std::vector<uint8_t> output_data(available_size);
    read_adaptor.read(output_data.data(), available_size);

    return output_data;
}

