#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer (std::vector<uint8_t>)
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Iterate through each chunk
    for (const auto& chunk : chunks) {
        // Use free() to check available space before each write
        if (adaptor.free() < chunk.size()) {
            // Handle insufficient space - resize buffer or throw error
            buffer.resize(buffer.size() + chunk.size());
            // Re-create adaptor with resized buffer
            adaptor = hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>>(buffer);
        }

        // Write the chunk data using write()
        adaptor.write(chunk.data(), chunk.size());
    }

    // Return the final buffer size using size()
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a result vector to accumulate read data
    std::vector<uint8_t> result;

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Use size() to check remaining data before each read
    while (adaptor.size() > 0) {
        // Determine current read chunk size (min of requested chunk_size and remaining data)
        std::size_t current_chunk_size = std::min(chunk_size, adaptor.size());

        // Create temporary buffer for reading
        std::vector<uint8_t> temp(current_chunk_size);

        // Read data using read()
        adaptor.read(temp.data(), current_chunk_size);

        // Append read data to result
        result.insert(result.end(), temp.begin(), temp.end());

        // Continue until buffer is empty
    }

    return result;
}
