struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert from native to little-endian
        adaptor.write(sensor_id);

        for (auto temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        adaptor.read(sensor_id);

        // Read all temperatures
        size_t temp_count = temperatures.size();
        for (size_t i = 0; i < temp_count; ++i) {
            float temp;
            adaptor.read(&temp);
            hexi::endian::little_to_native_inplace(temp);
            temperatures[i] = temp;
        }

        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create buffer and adaptor
